import{c as r,a7 as a,y as n,B as t}from"./chunks/framework.3cjvm90C.js";const d=JSON.parse('{"title":"Deep Q-Learning","description":"介绍深度 Q 网络的架构设计、经验回放与目标网络机制","frontmatter":{"title":"Deep Q-Learning","description":"介绍深度 Q 网络的架构设计、经验回放与目标网络机制"},"headers":[],"relativePath":"rlwiki/hfrlclass/ch3_dqn.md","filePath":"rlwiki/hfrlclass/ch3_dqn.md","lastUpdated":1782448598000}'),p={name:"rlwiki/hfrlclass/ch3_dqn.md"};function g(s,e,l,i,o,c){return a(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="deep-q-learning" tabindex="-1">Deep Q Learning <a class="header-anchor" href="#deep-q-learning" aria-label="Permalink to “Deep Q Learning”">​</a></h1><p><a href="https://huggingface.co/blog/deep-rl-q-part2" target="_blank" rel="noreferrer">在上一单元</a>中，我们学习了第一个强化学习算法： Q-Learning， <strong>从头开始实现它</strong>，并在 FrozenLake-v1 ☃️ 和 Taxi-v3 🚕 两个环境中对其进行训练。</p><p>我们用这个简单的算法得到了很好的结果。但是这些环境相对简单，因为<strong>状态空间是离散的且很小</strong>（FrozenLake-v1 有 14 个不同的状态， Taxi-v3 有 500 个）。</p><p>但正如我们将看到的，在非常大的状态空间环境中生成和更新 <strong>Q Table 可能变得不可能。</strong></p><p>所以今天，<strong>我们将研究我们的第一个深度强化学习智能体</strong>： Deep Q-Learning。Deep Q-Learning 不使用 Q Table，而是使用神经网络，该神经网络输入状态并根据该状态为每个动作近似 Q 值。</p><p>我们将使用 RL-Zoo 训练它玩 Space Invaders 和其他 Atari 环境， RL<a href="https://github.com/DLR-RM/rl-baselines3-zoo" target="_blank" rel="noreferrer">-Zoo</a>是一种基于 Stable-Baselines 的 RL 训练框架，它提供用于训练、评估智能体、调整超参数、绘制结果和录制视频的脚本。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/atari-envs.gif" alt="环境"></p><h2 id="从-q-learning-到-deep-q-learning" tabindex="-1">从 Q-Learning 到 Deep Q-Learning <a class="header-anchor" href="#从-q-learning-到-deep-q-learning" aria-label="Permalink to “从 Q-Learning 到 Deep Q-Learning”">​</a></h2><p>我们知道<strong>Q-Learning 是一种用于训练 Q-Function 的算法， Q-Function</strong>是<strong>动作价值函数</strong> ，可确定处于特定状态并在该状态下采取特定动作的价值。</p><p><img src="https://huggingface.co/blog/assets/73_deep_rl_q_part2/Q-function.jpg" alt="Q 函数"><em>给定状态和动作， Q 函数输出状态-动作值（也称为 Q 值)</em></p><p><strong>Q 来自该状态下该动作的“质量”</strong>。</p><p>在内部，我们的 Q 函数有 <strong>一个 Q Table，该表中每个单元格对应一个状态-动作对值。</strong> 将此 Q Table 视为 <strong>Q 函数的内存或备忘表。</strong></p><p>问题是 Q-Learning 是一种表格方法。Aka，一个状态空间和动作空间小到足以将值函数表示为数组和表的问题。这是不可扩展的。</p><p>Q-Learning 在小型状态空间环境中运行良好，例如：</p><ul><li>FrozenLake，有 14 个状态。</li><li>Taxi-v3，有 500 个状态。</li></ul><p>但是想一想我们今天要做的事情：我们将训练一个智能体来学习使用图像帧作为输入来玩 Space Invaders 游戏。</p><p>Atari 环境有一个形状为 (210, 160, 3) 的观察空间，每个像素包含从 0 到 255 的值，因此我们得到 256^(210x160x3) = 256^100800 个状态空间（为了比较，宇宙中的原子大约有 10^80 个）。</p><ul><li>Atari 中的单个帧由 210x160 像素的图像组成。鉴于图像是彩色的 (RGB)，有 3 个通道。这就是形状为 (210, 160, 3) 的原因。对于每个像素，该值可以从 0 到 255。</li></ul><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/atari.jpg" alt="Atari 状态空间"></p><p>因此，状态空间是巨大的；为该环境创建和更新 Q Table 几乎是不可实现的。在这种情况下，最好的办法是使用参数化 Q 函数 $Q_{\\theta}(s,a)$来近似 Q 值而不是 Q Table .</p><p>在给定状态的情况下，神经网络将近似估计该状态下每个可能动作的不同 Q 值。而这正是 Deep Q-Learning 所做的。</p><p><img src="https://huggingface.co/blog/assets/63_deep_rl_intro/deep.jpg" alt="Deep Q-Learning"></p><p>现在我们了解了 Deep Q -learning，下面让我们更深入地学习 Deep Q Network。</p><h2 id="deep-q-network-dqn" tabindex="-1">Deep Q Network (DQN) <a class="header-anchor" href="#deep-q-network-dqn" aria-label="Permalink to “Deep Q Network (DQN)”">​</a></h2><p>这是我们的 Deep Q-Learning 网络架构：</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/deep-q-network.jpg" alt="DeepQ 网络"></p><p>作为输入，我们将通过网络<strong>的 4 帧堆栈作为状态 State，并为该状态下的每个可能动作输出 Q 值向量</strong>。然后，就像 Q-Learning 一样，我们只需要使用我们的 epsilon-greedy 策略来选择要采取的行动。</p><p>初始化神经网络时，<strong>Q 值的估计很差</strong>。但在训练过程中，我们的 Deep Q Network 智能体会将情况与适当的行动联系起来，并<strong>学会玩好游戏</strong>。</p><h3 id="预处理输入和时间限制" tabindex="-1">预处理输入和时间限制 <a class="header-anchor" href="#预处理输入和时间限制" aria-label="Permalink to “预处理输入和时间限制”">​</a></h3><p>我们提到了对输入进行预处理。这是一个重要的步骤，因为我们希望降低状态的复杂性，以减少训练所需的计算时间。</p><p>因此，我们所做的是将状态空间减少到 84x84 并对其进行灰度处理（因为 Atari 环境中的颜色不会增加重要信息）。这是一个重要的节省，因为我们将三个颜色通道（RGB）减少到 1。</p><p>如果屏幕上不包含重要信息，我们也可以在某些游戏中裁剪屏幕的一部分。然后我们将四个帧叠加在一起。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/preprocessing.jpg" alt="预处理"></p><p>为什么我们要将四个帧叠加在一起？我们将帧堆叠在一起，因为它可以帮助我们<strong>处理时间限制的问题</strong>。让我们以 Pong 游戏为例。当您看到此帧时：</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/temporal-limitation.jpg" alt="时间限制"></p><p>你能告诉我，球的去向吗？不会，因为一帧不足以产生运动感！但是如果我再添加三个帧呢？<strong>在这里您可以看到球向右移动</strong>。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/temporal-limitation-2.jpg" alt="时间限制">这就是为什么, 为了捕获时间信息，我们将四个帧堆叠在一起。</p><p>然后，堆叠的帧由三个卷积层处理。这些层<strong>使我们能够捕获和利用图像中的空间关系</strong>。而且，由于帧堆叠在一起，因此可以利用这些帧的一些空间属性。</p><p>最后，我们有几个全连接层，它们为该状态下的每个可能动作输出 Q 值。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/deep-q-network.jpg" alt="DeepQ 网络"></p><p>我们看到 Deep Q-Learning 使用神经网络来近似给定状态下每个可能动作的不同 Q-值。接下来我们深入研究 Deep Q-Learning 算法。</p><h2 id="deep-q-learning-算法" tabindex="-1">Deep Q-Learning 算法 <a class="header-anchor" href="#deep-q-learning-算法" aria-label="Permalink to “Deep Q-Learning 算法”">​</a></h2><p>我们了解到， Deep Q-Learning 使用 Deep Network 来近似状态下每个可能动作的不同 Q-值（值函数估计）。 不同之处在于，在训练阶段，不像我们使用 Q-Learning 那样直接更新状态-动作对的 Q-值：</p><p><img src="https://huggingface.co/blog/assets/73_deep_rl_q_part2/q-ex-5.jpg" alt="Q 损失"></p><p>在 Deep Q-Learning 中，我们<strong>在 Q 值预测和 Q 目标之间创建了一个损失函数，并使用梯度下降来更新 Deep Q Network 的权重以更好地逼近我们的 Q 值</strong>。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/Q-target.jpg" alt="Q-目标"></p><p>Deep Q-Learning 训练算法有<em>两个阶段</em>：</p><ul><li><strong>采样</strong>：我们执行动作并将<strong>观察到的经验元组存储在 replay memory 中</strong>。</li><li><strong>训练</strong>：随机选择<strong>小批量的 Tuple 并使用梯度下降进行更新</strong>。</li></ul><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/sampling-training.jpg" alt="抽样训练"></p><p>但是，与 Q-Learning 相比，这并不是唯一的变化。Deep Q-Learning 训练<strong>可能会遇到不稳定</strong>的问题，这主要是因为结合了非线性 Q 值函数（神经网络）和 BootStrap （当我们使用现有估计而不是实际的完整回报来更新目标时）。</p><p>为了帮助我们稳定训练，我们实施了三种不同的解决方案：</p><ol><li><em>Experience Replay</em>，更<strong>有效地利用经验</strong>。</li><li>固定 Q-Target <strong>以稳定训练</strong>。</li><li><em>Double Deep Q-Learning</em>，<strong>处理 Q 值高估的问题</strong>。</li></ol><h3 id="经验回放-以更有效地利用数据" tabindex="-1">经验回放 以更有效地利用数据 <a class="header-anchor" href="#经验回放-以更有效地利用数据" aria-label="Permalink to “经验回放 以更有效地利用数据”">​</a></h3><p>我们为什么要创建经验回放？</p><p>Deep Q-Learning 中的 Experience Replay 有两个作用：</p><ol><li><strong>更有效地利用训练期间的经验</strong>。</li></ol><ul><li>经验回放有助于我们 <strong>更有效地利用训练期间的经验。</strong> 通常，在在线强化学习中，我们在环境中进行交互，获得经验（状态、动作、奖励和下一个状态），从中学习（更新神经网络）并丢弃它们。</li><li>但是通过经验回放，我们创建了一个回放缓冲区来保存<strong>我们可以在训练期间重复使用的经验样本。</strong></li></ul><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/experience-replay.jpg" alt="经验回放"></p><p>⇒ 这使我们能够<strong>多次从个人经验中学习</strong>。</p><ol start="2"><li><strong>避免忘记以前的经验，减少经验之间的相关性</strong>。</li></ol><ul><li>如果我们向神经网络提供连续的经验样本，我们会遇到的问题是，当它覆盖新的经验时，它往往会忘记以前的经验。</li></ul><p>解决方案是创建一个 Replay Buffer，在与环境交互时存储经验元组，然后对一小批元组进行采样。这可以防止 <strong>网络只了解它立即做了什么。</strong></p><p>经验回放还有其他好处。通过对经验进行随机抽样，我们消除了观察序列中的相关性，并避免了 <strong>动作值发生灾难性的振荡或发散。</strong></p><p>在 Deep Q-Learning 伪代码中，我们看到我们从容量 N （N 是您可以定义的超参数）<strong>初始化一个 Replay Buffer D。</strong>然后，我们将经验存储在内存中，并对一小批经验进行采样，以在训练阶段为 Deep Q Network 提供数据。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/experience-replay-pseudocode.jpg" alt="体验重放伪代码"></p><h3 id="固定-q-target-以稳定训练" tabindex="-1">固定 Q-Target 以稳定训练 <a class="header-anchor" href="#固定-q-target-以稳定训练" aria-label="Permalink to “固定 Q-Target 以稳定训练”">​</a></h3><p>当我们想要计算 TD 误差（也称损失）时，我们需要计算<strong>TD 目标（Q 目标）和当前 Q 值（Q 的估计）之间的差异</strong>。</p><p>但我们<strong>对真正的 TD 目标一无所知</strong>。我们需要做出估计。使用 Bellman 方程，我们看到 TD 目标只是在该状态下采取该动作的奖励加上下一个状态的折扣的最高 Q 值。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/Q-target.jpg" alt="Q-目标"></p><p>然而，问题在于我们使用相同的参数（权重）来估计 TD 目标 <strong>和</strong> Q 值。因此， TD 目标与我们正在更新的参数之间存在显着相关性。</p><p>因此，这意味着在训练的每一步， <strong>我们的 Q 值都会发生变化，但目标值也会发生变化。</strong> 所以，我们越来越接近我们的目标，但目标也在移动。这就像追逐一个移动的目标！导致了训练中的大幅振荡。</p><p>这就好比你是一个牛仔（Q 估计）并且你想抓住牛（Q 目标），你的目标是靠得更近（减少错误）。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/qtarget-1.jpg" alt="Q-目标"></p><p>在每个时间步，您都试图接近奶牛，奶牛也在每个时间步移动（因为使用相同的参数）。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/qtarget-2.jpg" alt="Q-目标"></p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/qtarget-3.jpg" alt="Q-目标"></p><p>这导致了奇怪的追逐路径（训练中的显著振荡）。</p><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/qtarget-4.jpg" alt="Q-目标"></p><p>相反，我们在伪代码中看到的是：</p><ul><li>使用<strong>固定参数的单独网络</strong>来估计 TD 目标</li><li><strong>间隔每个 C 步， 从 Deep Q Network 复制参数</strong>以更新目标网络。</li></ul><p><img src="https://huggingface.co/blog/assets/78_deep_rl_dqn/fixed-q-target-pseudocode.jpg" alt="固定 Q-target 伪代码"></p><h3 id="double-dqn" tabindex="-1">Double-DQN <a class="header-anchor" href="#double-dqn" aria-label="Permalink to “Double-DQN”">​</a></h3><p>Double DQN 或者 Double Q-learning， <a href="https://papers.nips.cc/paper/3964-double-q-learning" target="_blank" rel="noreferrer">由 Hado van Hasselt</a>引入。该方法 <strong>解决了 Q 值高估的问题。</strong></p><p>要理解这个问题，请记住我们如何计算 TD Target：</p><p>通过计算 TD 目标， 我们面临一个简单的问题：如何确定 <strong>下一个状态的最佳动作是具有最高 Q 值的动作？</strong></p><p>我们知道， Q 值的准确性取决于我们尝试了什么动作 <strong>以及</strong> 我们探索了哪些相邻状态。</p><p>因此，在训练开始时，我们没有足够的关于最佳行动的信息 。因此，将最大 Q 值（有噪声）作为最佳动作可能会导致误报。如果非最优动作经常 <strong>被赋予比最优最佳动作更高的 Q 值，学习将变得复杂。</strong></p><p>解决方案是：当我们计算 Q 目标时，我们使用两个网络将动作选择与目标 Q 值生成解耦。我们：</p><ul><li>使用<strong>DQN 网络</strong>为下一个状态选择最佳动作（具有最高 Q 值的动作）。</li><li>使用<strong>目标网络</strong>来计算在下一个状态下采取该动作的目标 Q 值。</li></ul><p>因此， Double DQN 有助我们减少对 q 值的高估，从而帮助我们训练得更快，更稳定。</p><p>自 Deep Q-Learning 的这三项改进以来，又增加了很多新的改进，例如 Prioritized Experience Replay、Dueling Deep Q-Learning。它们超出了本课程的范围，但如果您有兴趣，请查看我们放在阅读列表中的链接。👉 <strong><a href="https://github.com/huggingface/deep-rl-class/blob/main/unit3/README.md" target="_blank" rel="noreferrer">https://github.com/huggingface/deep-rl-class/blob/main/unit3/README.md</a></strong></p><h2 id="补充阅读" tabindex="-1">补充阅读 <a class="header-anchor" href="#补充阅读" aria-label="Permalink to “补充阅读”">​</a></h2><ul><li><a href="https://youtu.be/Psrhxy88zww" target="_blank" rel="noreferrer">Foundations of Deep RL Series, L2 Deep Q-Learning by Pieter Abbeel</a></li><li><a href="https://arxiv.org/abs/1312.5602" target="_blank" rel="noreferrer">Playing Atari with Deep Reinforcement Learning</a></li><li><a href="https://papers.nips.cc/paper/2010/hash/091d584fced301b442654dd8c23b3fc9-Abstract.html" target="_blank" rel="noreferrer">Double Deep Q-Learning</a></li><li><a href="https://arxiv.org/abs/1511.05952" target="_blank" rel="noreferrer">Prioritized Experience Replay</a></li></ul>',93)])])}const Q=r(p,[["render",g]]);export{d as __pageData,Q as default};
